import { useEffect, useMemo, useState } from 'preact/hooks'
import { route } from 'preact-router'
import { Button } from '@web/components/ui/button'
import { Checkbox } from '@web/components/ui/checkbox'
import { Input } from '@web/components/ui/input'
import { fetchJson } from '@web/lib/api'
import type { ReportSettingView, RepoRow } from '@web/pages/report/types'

const ROUTES = [
  {
    href: '/report',
    label: '日报',
    title: '日报台账',
    desc: '查改归档、任务分布饼图、名单与偏好。',
    hint: 'Report',
  },
  {
    href: '/bench',
    label: '测速',
    title: '网关测速',
    desc: '对比模型首包与总耗时，定时探测看稳定性。',
    hint: 'Bench',
  },
  {
    href: '/setting',
    label: '设置',
    title: 'AI 配置',
    desc: '全局网关与模型，供 gc、report、agent 共用。',
    hint: 'Setting',
  },
] as const

export { ROUTES }

export function HomePage(_props: { path?: string }) {
  const [repos, setRepos] = useState<RepoRow[]>([])
  const [selected, setSelected] = useState<Record<string, boolean>>({})
  const [extraPath, setExtraPath] = useState('')
  const [append, setAppend] = useState('')
  const [busy, setBusy] = useState(false)
  const [msg, setMsg] = useState('')

  const picked = useMemo(
    () => repos.filter((r) => selected[r.path]).map((r) => r.path),
    [repos, selected],
  )

  useEffect(() => {
    void fetchJson<ReportSettingView>('/api/report/setting')
      .then((s) => {
        setRepos(s.repositories || [])
        setSelected(
          Object.fromEntries((s.repositories || []).map((r) => [r.path, !!r.enabled])),
        )
      })
      .catch(() => {
        /* 首页不拦 */
      })
  }, [])

  async function generate() {
    setBusy(true)
    setMsg('生成中…（读 commit + AI，可能要半分钟）')
    try {
      const paths = [...picked]
      if (extraPath.trim()) paths.push(extraPath.trim())
      const data = await fetchJson<{
        record: { date: string }
        gather?: { commitCount: number; repos: number }
      }>('/api/report/generate', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          paths: paths.length ? paths : undefined,
          append: append.trim() || undefined,
        }),
      })
      setMsg(
        `完成 · ${data.gather?.repos ?? 0} 仓 · ${data.gather?.commitCount ?? 0} commits`,
      )
      route(`/report/history/${data.record.date}`)
    } catch (e) {
      setMsg(e instanceof Error ? e.message : String(e))
    } finally {
      setBusy(false)
    }
  }

  return (
    <div class="space-y-12">
      <section class="animate-rise max-w-2xl pt-2">
        <p class="font-display text-[clamp(3.2rem,10vw,5.2rem)] font-extrabold leading-[0.95] tracking-tight text-foreground">
          tkt
        </p>
        <h1 class="mt-5 text-[1.35rem] font-semibold tracking-tight text-foreground sm:text-[1.55rem]">
          本机工具，少打扰
        </h1>
        <p class="mt-3 max-w-md text-[0.95rem] leading-relaxed text-muted">
          日报台账、测网关、配模型，都在一个端口里。
        </p>
      </section>

      {/* 当天日报生成 */}
      <section class="animate-rise-delay-1 rounded-2xl border border-border/80 bg-card/90 p-5 shadow-[0_1px_0_rgba(18,21,26,0.04)] sm:p-6">
        <div class="mb-4 flex flex-wrap items-end justify-between gap-2">
          <div>
            <h2 class="font-display text-xl font-bold tracking-tight">生成今日日报</h2>
            <p class="mt-1 text-sm text-muted">
              只扫名单里已有仓库，或粘贴本地路径；不自动搜 cwd。
            </p>
          </div>
          <Button disabled={busy} onClick={() => void generate()}>
            {busy ? '生成中…' : '生成并归档'}
          </Button>
        </div>

        {repos.length ? (
          <div class="mb-4 grid max-h-40 grid-cols-1 gap-1.5 overflow-auto sm:grid-cols-2">
            {repos.map((r) => (
              <label
                key={r.path}
                class="flex cursor-pointer items-start gap-2 rounded-lg px-2 py-1.5 text-sm hover:bg-surface/80"
              >
                <Checkbox
                  class="mt-0.5"
                  checked={!!selected[r.path]}
                  onChange={(e) => {
                    const on = (e.target as HTMLInputElement).checked
                    setSelected((s) => ({ ...s, [r.path]: on }))
                  }}
                />
                <span class="min-w-0">
                  <span class="font-medium">
                    {r.display_name || r.alias}
                  </span>
                  <span class="mt-0.5 block truncate font-mono text-[11px] text-muted">
                    {r.path}
                  </span>
                </span>
              </label>
            ))}
          </div>
        ) : (
          <p class="mb-3 text-sm text-muted">名单为空时，请在下方输入仓库路径。</p>
        )}

        <div class="flex flex-col gap-2 sm:flex-row">
          <Input
            class="flex-1"
            value={extraPath}
            placeholder="或输入本地 git 路径，例如 /Users/me/proj"
            onInput={(e) => setExtraPath((e.target as HTMLInputElement).value)}
          />
          <Input
            class="flex-1"
            value={append}
            placeholder="附带杂事（可选）"
            onInput={(e) => setAppend((e.target as HTMLInputElement).value)}
          />
        </div>
        {msg ? (
          <p class={`mt-3 text-sm ${msg.includes('完成') ? 'text-success' : busy ? 'text-muted' : 'text-destructive'}`}>
            {msg}
          </p>
        ) : null}
      </section>

      <section class="animate-rise-delay-2 grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
        {ROUTES.map((item, i) => (
          <a
            key={item.href}
            href={item.href}
            onClick={(e) => {
              e.preventDefault()
              route(item.href)
            }}
            class={cnEntry(i)}
          >
            <div class="flex items-start justify-between gap-3">
              <h2 class="font-display text-xl font-bold tracking-tight">
                {item.title}
              </h2>
              <span
                class="mt-1 inline-flex size-8 shrink-0 items-center justify-center rounded-md bg-primary/10 text-primary transition-transform duration-300 group-hover:translate-x-0.5"
                aria-hidden
              >
                →
              </span>
            </div>
            <p class="mt-3 text-sm leading-relaxed text-muted">{item.desc}</p>
            <p class="mt-6 text-xs font-medium uppercase tracking-[0.14em] text-primary/70">
              {item.hint}
            </p>
          </a>
        ))}
      </section>
    </div>
  )
}

function cnEntry(i: number) {
  return [
    'group relative block overflow-hidden rounded-2xl border border-border/80 bg-card/90 p-6',
    'shadow-[0_1px_0_rgba(18,21,26,0.04)] backdrop-blur-sm',
    'transition-[transform,border-color,box-shadow] duration-300',
    'hover:-translate-y-0.5 hover:border-primary/35 hover:shadow-[0_12px_32px_-18px_rgba(26,95,122,0.45)]',
    i === 1 ? 'animate-rise-delay-1' : '',
    i === 2 ? 'animate-rise-delay-2' : '',
  ]
    .filter(Boolean)
    .join(' ')
}
